import triton
import triton.language as tl
import torch


@triton.jit
def _tanh_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(input_ptr + offsets, mask=mask)
    y = 2.0 * tl.sigmoid(2.0 * x) - 1.0
    tl.store(output_ptr + offsets, y, mask=mask)


def tanh(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if input.dtype not in (torch.float16, torch.bfloat16, torch.float32):
        raise TypeError("supported dtypes are float16, bfloat16, and float32")

    input_contig = input.contiguous()

    if out is None:
        result = torch.empty_like(input_contig)
        out_final = result
    else:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if not out.is_cuda:
            raise ValueError("out must be a CUDA tensor")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.dtype != input.dtype:
            raise ValueError("out must have the same dtype as input")
        out_final = out
        result = out if out.is_contiguous() else torch.empty_like(input_contig)

    n_elements = input_contig.numel()
    if n_elements > 0:
        grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
        _tanh_kernel[grid](
            input_contig,
            result,
            n_elements,
            BLOCK_SIZE=1024,
        )

    if out is not None and not out.is_contiguous():
        out.copy_(result)
        return out

    if out is None:
        if input_contig.data_ptr() != input.data_ptr() or input_contig.shape != input.shape or input_contig.stride() != input.stride():
            return result.view(input.shape)
        return result

    return out_final

