import triton
import triton.language as tl
import torch


@triton.jit
def _relu_sqrt_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < n_elements
    x = tl.load(input_ptr + offs, mask=mask)
    x = tl.maximum(x, 0)
    y = tl.sqrt(x)
    tl.store(output_ptr + offs, y, mask=mask)


@triton.jit
def _relu_inplace_kernel(
    input_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < n_elements
    x = tl.load(input_ptr + offs, mask=mask)
    x = tl.maximum(x, 0)
    tl.store(input_ptr + offs, x, mask=mask)


@triton.jit
def _sqrt_copy_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < n_elements
    x = tl.load(input_ptr + offs, mask=mask)
    y = tl.sqrt(x)
    tl.store(output_ptr + offs, y, mask=mask)


def relu_sqrt(input, inplace=False, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if not input.is_contiguous():
        raise ValueError("input must be contiguous")
    if input.dtype not in (torch.float16, torch.float32, torch.float64, torch.bfloat16):
        raise TypeError("input must have a floating-point dtype supported by torch.sqrt on CUDA")

    if out is not None:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if not out.is_cuda:
            raise ValueError("out must be a CUDA tensor")
        if not out.is_contiguous():
            raise ValueError("out must be contiguous")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.dtype != input.dtype:
            raise ValueError("out must have the same dtype as input")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")

    n_elements = input.numel()
    if n_elements == 0:
        if out is not None:
            return out
        if inplace:
            return input
        return torch.empty_like(input)

    BLOCK_SIZE = 1024
    grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)

    if inplace:
        if out is None or out.data_ptr() == input.data_ptr():
            _relu_sqrt_kernel[grid](input, input, n_elements, BLOCK_SIZE=BLOCK_SIZE)
            return input
        _relu_inplace_kernel[grid](input, n_elements, BLOCK_SIZE=BLOCK_SIZE)
        _sqrt_copy_kernel[grid](input, out, n_elements, BLOCK_SIZE=BLOCK_SIZE)
        return out

    if out is None:
        out = torch.empty_like(input)

    _relu_sqrt_kernel[grid](input, out, n_elements, BLOCK_SIZE=BLOCK_SIZE)
    return out

