import torch
import triton
import triton.language as tl


@triton.jit
def _sqrt_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(input_ptr + offsets, mask=mask)
    y = tl.sqrt(x)
    tl.store(output_ptr + offsets, y, mask=mask)


def sqrt(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if input.is_complex():
        raise TypeError("complex tensors are not supported")
    if not (input.dtype.is_floating_point or input.dtype == torch.bfloat16):
        raise TypeError("input must have a floating-point dtype")

    if out is not None:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if not out.is_cuda:
            raise ValueError("out must be a CUDA tensor")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.dtype != input.dtype:
            raise ValueError("out must have the same dtype as input")

    n_elements = input.numel()

    if out is None:
        out = torch.empty_like(input)

    if n_elements == 0:
        return out

    input_contig = input if input.is_contiguous() else input.contiguous()

    if out.is_contiguous():
        output_contig = out
        need_copy_back = False
    else:
        output_contig = torch.empty_like(input_contig)
        need_copy_back = True

    input_flat = input_contig.view(-1)
    output_flat = output_contig.view(-1)

    BLOCK_SIZE = 1024
    grid = (triton.cdiv(n_elements, BLOCK_SIZE),)

    _sqrt_kernel[grid](
        input_flat,
        output_flat,
        n_elements,
        BLOCK_SIZE=BLOCK_SIZE,
    )

    if need_copy_back:
        out.copy_(output_contig.view_as(out))

    return out

