        out = torch.empty_like(input)
    else:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if not out.is_cuda:
            raise ValueError("out must be a CUDA tensor")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.dtype not in (torch.float16, torch.bfloat16, torch.float32, torch.float64):
            raise TypeError("out must have a floating-point dtype")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")

    input_contig = input if input.is_contiguous() else input.contiguous()
    output_contig = out if out.is_contiguous() else torch.empty_like(out)

    n_elements = input.numel()
    if n_elements > 0:
        BLOCK_SIZE = 1024
        grid = (triton.cdiv(n_elements, BLOCK_SIZE),)
        _rsqrt_kernel[grid](
            input_contig,
            output_contig,
            n_elements,
            BLOCK_SIZE=BLOCK_SIZE,
        )

    if output_contig.data_ptr() != out.data_ptr():
        out.copy_(output_contig)

    return out

