import torch
import triton
import triton.language as tl


@triton.jit
def _relu_kernel(x_ptr, y_ptr, n_elements, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(x_ptr + offsets, mask=mask)
    zero = tl.zeros((BLOCK_SIZE,), dtype=x.dtype)
    y = tl.maximum(x, zero)
    tl.store(y_ptr + offsets, y, mask=mask)


def relu(input, inplace=False):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if not input.is_contiguous():
        raise ValueError("input must be contiguous")
    if input.dtype == torch.bool:
        raise TypeError("relu is not supported for bool tensors")
    if not inplace:
        output = torch.empty_like(input)
    else:
        output = input
    n_elements = input.numel()
    if n_elements == 0:
        return output
    grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
    _relu_kernel[grid](input, output, n_elements, BLOCK_SIZE=1024)
    return output

