import triton
import triton.language as tl
import torch


@triton.jit
def _value_better(new_val, new_idx, cur_val, cur_idx, IS_FLOAT: tl.constexpr):
    if IS_FLOAT:
        new_nan = tl.isnan(new_val)
        cur_nan = tl.isnan(cur_val)
        return tl.where(
            new_nan & ~cur_nan,
            True,
            tl.where(
                ~new_nan & cur_nan,
                False,
                tl.where(
                    new_nan & cur_nan,
                    new_idx < cur_idx,
                    (new_val > cur_val) | ((new_val == cur_val) & (new_idx < cur_idx)),
                ),
            ),
        )
    else:
        return (new_val > cur_val) | ((new_val == cur_val) & (new_idx < cur_idx))


@triton.jit
def _candidate_better(new_val, new_idx, new_valid, cur_val, cur_idx, cur_valid, IS_FLOAT: tl.constexpr):
    return (~cur_valid & new_valid) | (cur_valid & new_valid & _value_better(new_val, new_idx, cur_val, cur_idx, IS_FLOAT=IS_FLOAT))


@triton.jit
def _argmax_rows_kernel(
    x_ptr,
    out_ptr,
    M,
    K,
    stride_m,
    stride_k,
    out_stride,
    BLOCK: tl.constexpr,
    IS_FLOAT: tl.constexpr,
):
    pid = tl.program_id(0)
    if pid >= M:
        return

    offs = tl.arange(0, BLOCK)
    idxs = offs
    mask = idxs < K

    row_ptr = x_ptr + pid * stride_m
    vals = tl.load(row_ptr + idxs * stride_k, mask=mask, other=0)
    best_vals = vals
    best_idxs = idxs.to(tl.int64)
    best_valid = mask

    for start in tl.range(BLOCK, K, BLOCK):
        idxs = start + offs
        mask = idxs < K
        vals = tl.load(row_ptr + idxs * stride_k, mask=mask, other=0)
        cand_idxs = idxs.to(tl.int64)
        better = _candidate_better(vals, cand_idxs, mask, best_vals, best_idxs, best_valid, IS_FLOAT=IS_FLOAT)
        best_vals = tl.where(better, vals, best_vals)
        best_idxs = tl.where(better, cand_idxs, best_idxs)
        best_valid = best_valid | mask

    final_val = best_vals[0]
    final_idx = best_idxs[0]
    final_valid = best_valid[0]

    for i in tl.static_range(1, BLOCK):
        cand_val = best_vals[i]
        cand_idx = best_idxs[i]
        cand_valid = best_valid[i]
        better = _candidate_better(cand_val, cand_idx, cand_valid, final_val, final_idx, final_valid, IS_FLOAT=IS_FLOAT)
