import triton
import triton.language as tl
import torch


@triton.jit
def _value_better(new_val, new_idx, cur_val, cur_idx, IS_FLOAT: tl.constexpr):
    if IS_FLOAT:
        new_nan = tl.isnan(new_val)
        cur_nan = tl.isnan(cur_val)
        return tl.where(
            new_nan & ~cur_nan,
            True,
            tl.where(
                ~new_nan & cur_nan,
                False,
                tl.where(
                    new_nan & cur_nan,
                    new_idx < cur_idx,
                    (new_val > cur_val) | ((new_val == cur_val) & (new_idx < cur_idx)),
                ),
            ),
        )
    else:
        return (new_val > cur_val) | ((new_val == cur_val) & (new_idx < cur_idx))


@triton.jit
def _candidate_better(new_val, new_idx, new_valid, cur_val, cur_idx, cur_valid, IS_FLOAT: tl.constexpr):
    return (~cur_valid & new_valid) | (cur_valid & new_valid & _value_better(new_val, new_idx, cur_val, cur_idx, IS_FLOAT=IS_FLOAT))


