@triton.jit
def _log1p_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    FP64: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    x = tl.load(input_ptr + offsets, mask=mask)

    if FP64:
        x = x.to(tl.float64)
        y = tl.log(x + 1.0)
    else:
        x = x.to(tl.float32)
        y = tl.log(x + 1.0)

    tl.store(output_ptr + offsets, y, mask=mask)


def log1p(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if input.is_complex():
        raise NotImplementedError("complex tensors are not supported")
    if input.device.type != "cuda":
        raise ValueError("input must be a CUDA tensor")

    if input.is_floating_point():
        result_dtype = input.dtype
    else:
        result_dtype = torch.get_default_dtype()

    if out is None:
        result = torch.empty(input.shape, device=input.device, dtype=result_dtype)
        out_target = result
        needs_copy_back = False
    else:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")
        if tuple(out.shape) != tuple(input.shape):
            raise ValueError("out must have the same shape as input")
        if out.dtype != result_dtype:
            raise ValueError("out has incorrect dtype")
        result = out
        out_target = out
        needs_copy_back = not out.is_contiguous()

    input_contig = input if input.is_contiguous() else input.contiguous()

    if needs_copy_back:
        temp_out = torch.empty_like(out_target, memory_format=torch.contiguous_format)
        kernel_out = temp_out
    else:
        kernel_out = out_target if out_target.is_contiguous() else out_target.contiguous()

    n_elements = input_contig.numel()
    if n_elements == 0:
        if needs_copy_back:
            out_target.copy_(kernel_out)
        return out_target

    BLOCK_SIZE = 1024
    grid = (triton.cdiv(n_elements, BLOCK_SIZE),)
    fp64 = result_dtype == torch.float64

    _log1p_kernel[grid](
        input_contig.reshape(-1),
        kernel_out.reshape(-1),
        n_elements,
        FP64=fp64,
        BLOCK_SIZE=BLOCK_SIZE,
    )

    if needs_copy_back:
        out_target.copy_(kernel_out)

    return out_target

