import triton
import triton.language as tl
import torch


@triton.jit
def _logit_kernel(
    x_ptr,
    y_ptr,
    n_elements,
    eps,
    HAS_EPS: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < n_elements

    x = tl.load(x_ptr + offs, mask=mask).to(tl.float32)

    if HAS_EPS:
        one = 1.0
        x = tl.maximum(x, eps)
        x = tl.minimum(x, one - eps)

    y = tl.log(x / (1.0 - x))
    tl.store(y_ptr + offs, y, mask=mask)


def logit(input, eps=None, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a Tensor")
    if not input.is_floating_point():
        raise TypeError("logit only supports floating-point input tensors")
    if input.device.type not in ("cuda", "hip"):
        raise ValueError("input must be on a CUDA or HIP device")

    if eps is not None:
        eps = float(eps)

    if out is not None:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a Tensor")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")
        if not out.is_floating_point():
            raise TypeError("out must be a floating-point tensor")

    x = input.contiguous() if not input.is_contiguous() else input

    need_temp_out = out is None or not out.is_contiguous() or out.dtype != input.dtype
    if need_temp_out:
        y = torch.empty_like(x)
    else:
        y = out if x.data_ptr() != out.data_ptr() or x.shape == out.shape else out

    n_elements = x.numel()
    if n_elements > 0:
        BLOCK_SIZE = 1024
        grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
        if eps is None:
            _logit_kernel[grid](
                x,
                y,
                n_elements,
                0.0,
                HAS_EPS=False,
                BLOCK_SIZE=BLOCK_SIZE,
            )
        else:
            _logit_kernel[grid](
                x,
                y,
                n_elements,
                eps,
                HAS_EPS=True,
                BLOCK_SIZE=BLOCK_SIZE,
            )

    if out is not None:
        if y.data_ptr() != out.data_ptr():
            out.copy_(y)
        return out
    return y

