        raise TypeError("complex input is not supported")
    if input.dtype not in (torch.float16, torch.bfloat16, torch.float32, torch.float64):
        raise TypeError("input dtype must be float16, bfloat16, float32, or float64")

    x = input.contiguous()
    n_elements = x.numel()

    if out is None:
        result = torch.empty_like(x)
        out_target = None
    else:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor or None")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.is_complex():
            raise TypeError("complex out is not supported")
        if out.dtype not in (torch.float16, torch.bfloat16, torch.float32, torch.float64):
            raise TypeError("out dtype must be float16, bfloat16, float32, or float64")
        if out.is_contiguous():
            result = out
            out_target = out
        else:
            result = torch.empty_like(x, dtype=out.dtype)
            out_target = out

