import torch
from typing import Iterable

_SGD_STATE = {}


@triton.jit
def _sgd_basic_kernel(
    p_ptr,
    g_ptr,
    n_elements,
    lr,
    weight_decay,
    maximize_flag: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    p = tl.load(p_ptr + offsets, mask=mask)
    g = tl.load(g_ptr + offsets, mask=mask)

    if weight_decay != 0:
        g = g + weight_decay * p

    if maximize_flag:
        p_new = p + lr * g
    else:
        p_new = p - lr * g

    tl.store(p_ptr + offsets, p_new, mask=mask)


@triton.jit
def _sgd_momentum_kernel(
    p_ptr,
    g_ptr,
    buf_ptr,
    n_elements,
    lr,
    momentum,
    weight_decay,
    dampening,
    maximize_flag: tl.constexpr,
    nesterov_flag: tl.constexpr,
    first_step_flag: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    p = tl.load(p_ptr + offsets, mask=mask)
    g = tl.load(g_ptr + offsets, mask=mask)

    if weight_decay != 0:
        g = g + weight_decay * p

    if first_step_flag:
        buf = g
    else:
        buf_prev = tl.load(buf_ptr + offsets, mask=mask)
        buf = momentum * buf_prev + (1.0 - dampening) * g

    tl.store(buf_ptr + offsets, buf, mask=mask)

    if nesterov_flag:
        g_eff = g + momentum * buf
    else:
        g_eff = buf

    if maximize_flag:
        p_new = p + lr * g_eff
    else:
        p_new = p - lr * g_eff

    tl.store(p_ptr + offsets, p_new, mask=mask)


def _as_param_list(params):
    if isinstance(params, torch.Tensor):
        return [params]
    if isinstance(params, Iterable):
        return list(params)
    raise TypeError("params must be a Tensor or an iterable of Tensors")


def _get_state_key(param):
    return id(param)


def _get_or_create_buffer(param):
    key = _get_state_key(param)
    state = _SGD_STATE.get(key)
    if state is None or state["buffer"].shape != param.shape or state["buffer"].dtype != param.dtype or state["buffer"].device != param.device:
        buf = torch.empty_like(param)
        _SGD_STATE[key] = {"buffer": buf, "initialized": False}
    return _SGD_STATE[key]


def SGD(params, lr=1e-3, momentum=0, weight_decay=0, dampening=0, nesterov=False, maximize=False, foreach=None, differentiable=False, fused=None):
    if differentiable:
        raise NotImplementedError("differentiable=True is not supported")
    if foreach not in (None, False):
        raise NotImplementedError("foreach=True is not supported")
    if fused not in (None, False):
        raise NotImplementedError("fused=True is not supported")
    if momentum < 0:
        raise ValueError("Invalid momentum value")
    if weight_decay < 0:
        raise ValueError("Invalid weight_decay value")
    if lr < 0:
        raise ValueError("Invalid learning rate")
    if nesterov and (momentum <= 0 or dampening != 0):
        raise ValueError("Nesterov momentum requires a momentum and zero dampening")

    param_list = _as_param_list(params)
    if len(param_list) == 0:
        return None

    for param in param_list:
        if not isinstance(param, torch.Tensor):
            raise TypeError("all params must be torch.Tensor")
        if param.grad is None:
            continue
        if not param.is_cuda:
            raise ValueError("all params must be CUDA tensors")
        if not param.grad.is_cuda:
            raise ValueError("all grads must be CUDA tensors")
        if param.is_sparse or param.grad.is_sparse:
            raise NotImplementedError("sparse tensors are not supported")
        if not param.is_contiguous():
            raise ValueError("params must be contiguous")
        if not param.grad.is_contiguous():
            raise ValueError("grads must be contiguous")
        if param.numel() != param.grad.numel():
            raise ValueError("param and grad must have the same number of elements")

        n = param.numel()
        if n == 0:
            continue

        BLOCK_SIZE = 1024
        grid = (triton.cdiv(n, BLOCK_SIZE),)

        if momentum == 0:
            _sgd_basic_kernel[grid](
                param,
                param.grad,
                n,
                lr,
                weight_decay,
                maximize_flag=bool(maximize),
                BLOCK_SIZE=BLOCK_SIZE,
            )
        else:
            state = _get_or_create_buffer(param)
            first_step = not state["initialized"]
            _sgd_momentum_kernel[grid](
                param,
                param.grad,
                state["buffer"],
                n,
                lr,
                momentum,
                weight_decay,
                dampening,
                maximize_flag=bool(maximize),
                nesterov_flag=bool(nesterov),
                first_step_flag=bool(first_step),
                BLOCK_SIZE=BLOCK_SIZE,
            )
            state["initialized"] = True

    return None

