import triton
import triton.language as tl
import torch
import math


def _normalize_dims(dim, ndim):
    if isinstance(dim, int):
        dims = (dim,)
    else:
        dims = tuple(dim)
    norm = []
    seen = set()
    for d in dims:
        if d < 0:
            d += ndim
        if d < 0 or d >= ndim:
            raise IndexError("Dimension out of range")
        if d in seen:
            raise RuntimeError("dim appears multiple times in the list of dims")
        seen.add(d)
        norm.append(d)
    return tuple(norm)


def _prod(seq):
    r = 1
    for x in seq:
        r *= int(x)
    return r


def _infer_sum_dtype(input_dtype, dtype):
    if dtype is not None:
        return dtype
    if input_dtype in (
        torch.uint8,
        torch.int8,
        torch.int16,
        torch.int32,
        torch.int64,
        torch.bool,
    ):
        return torch.int64
    return input_dtype


def _acc_kind_from_dtype(dtype):
    if dtype == torch.float16:
        return 0
    if dtype == torch.bfloat16:
        return 1
    if dtype == torch.float32:
        return 2
    if dtype == torch.float64:
        return 3
    if dtype == torch.int32:
        return 4
    if dtype == torch.int64:
        return 5
    if dtype == torch.bool:
        return 6
    raise NotImplementedError(f"Unsupported dtype for accumulation: {dtype}")


def _out_kind_from_dtype(dtype):
    if dtype == torch.float16:
        return 0
    if dtype == torch.bfloat16:
        return 1
    if dtype == torch.float32:
        return 2
    if dtype == torch.float64:
        return 3
    if dtype == torch.int32:
        return 4
    if dtype == torch.int64:
        return 5
    if dtype == torch.bool:
        return 6
    raise NotImplementedError(f"Unsupported output dtype: {dtype}")


