def _to_acc(x, ACC_KIND: tl.constexpr):
    if ACC_KIND == 0:
        return x.to(tl.float16)
    elif ACC_KIND == 1:
        return x.to(tl.bfloat16)
    elif ACC_KIND == 2:
        return x.to(tl.float32)
    elif ACC_KIND == 3:
        return x.to(tl.float64)
    elif ACC_KIND == 4:
        return x.to(tl.int32)
    elif ACC_KIND == 5:
        return x.to(tl.int64)
    else:
        return x.to(tl.int32)


