        acc_dtype = torch.float32
    elif out_dtype == torch.bfloat16:
        acc_dtype = torch.float32
    elif out_dtype == torch.float32:
        acc_dtype = torch.float32
    elif out_dtype == torch.float64:
        acc_dtype = torch.float64
    elif out_dtype == torch.int32:
        acc_dtype = torch.int32
    elif out_dtype == torch.int64:
        acc_dtype = torch.int64
    elif out_dtype == torch.bool:
        acc_dtype = torch.int32
    else:
        raise NotImplementedError(f"Unsupported output dtype: {out_dtype}")

    if M == 0:
        out_flat = torch.empty((0,), device=input.device, dtype=out_dtype)
    else:
        out_flat = torch.empty((M,), device=input.device, dtype=out_dtype)
        BLOCK_K = 1024
        grid = (M,)
        _sum_rows_kernel[grid](
            x.reshape(M, K),
            out_flat,
            M,
            K,
            BLOCK_K=BLOCK_K,
            ACC_KIND=_acc_kind_from_dtype(acc_dtype),
            OUT_KIND=_out_kind_from_dtype(out_dtype),
        )

    if keepdim:
        out_shape = []
        kept_set = set(kept_dims)
