            out_flat,
            M,
            K,
            BLOCK_K=BLOCK_K,
            ACC_KIND=_acc_kind_from_dtype(acc_dtype),
            OUT_KIND=_out_kind_from_dtype(out_dtype),
        )

    if keepdim:
        out_shape = []
        kept_set = set(kept_dims)
        for i in range(ndim):
            if i in kept_set:
                out_shape.append(input.shape[i])
            else:
                out_shape.append(1)
    else:
        out_shape = kept_shape

    return out_flat.reshape(out_shape)

