@triton.jit
def _sigmoid_kernel(
    x_ptr,
    y_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(x_ptr + offsets, mask=mask)
    y = tl.sigmoid(x)
    tl.store(y_ptr + offsets, y, mask=mask)


def sigmoid(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if input.device.type != "cuda":
        raise ValueError("input must be a CUDA tensor")
    if not input.is_floating_point():
        raise TypeError("sigmoid is only implemented for floating-point CUDA tensors")
    if out is not None:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")
        if out.shape != input.shape:
            raise ValueError("out must have the same shape as input")
        if out.dtype != input.dtype:
            raise ValueError("out must have the same dtype as input")

    if out is None:
        out = torch.empty_like(input)

    n_elements = input.numel()
    if n_elements == 0:
        return out

    x = input if input.is_contiguous() else input.contiguous()

    if out.is_contiguous():
        y = out
        need_copy_back = False
    else:
        y = torch.empty_like(input, memory_format=torch.contiguous_format)
        need_copy_back = True

    grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
    _sigmoid_kernel[grid](
        x,
        y,
        n_elements,
        BLOCK_SIZE=1024,
    )

    if need_copy_back:
        out.copy_(y)

    return out

