import triton
import triton.language as tl
import torch


@triton.jit
def _erf_kernel(
    in_ptr,
    out_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
    COMPUTE_FP32: tl.constexpr,
):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    x = tl.load(in_ptr + offsets, mask=mask)
    if COMPUTE_FP32:
        x = x.to(tl.float32)

    sign = tl.where(x < 0, -1.0, 1.0)
    ax = tl.abs(x)

    p = 0.3275911
    a1 = 0.254829592
    a2 = -0.284496736
    a3 = 1.421413741
    a4 = -1.453152027
    a5 = 1.061405429

    t = 1.0 / (1.0 + p * ax)
    poly = (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t
    y = sign * (1.0 - poly * tl.exp(-(ax * ax)))

    tl.store(out_ptr + offsets, y, mask=mask)


def erf(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if input.is_complex():
        raise TypeError("complex inputs are not supported")
    if input.numel() == 0:
        if out is not None:
            if out.shape != input.shape:
                raise ValueError("out must have the same shape as input")
            return out
        if input.dtype.is_floating_point:
            return torch.empty_like(input)
        return torch.empty(input.shape, device=input.device, dtype=torch.get_default_dtype())

    if input.dtype.is_floating_point:
        x = input
    else:
        x = input.to(torch.get_default_dtype())

    x_contig = x.contiguous()
    need_temp_out = out is None or (not out.is_contiguous()) or out.dtype != x_contig.dtype or out.shape != x_contig.shape or out.device != x_contig.device

    if out is None:
        out_tensor = torch.empty_like(x_contig)
    elif need_temp_out:
        out_tensor = torch.empty_like(x_contig)
    else:
        out_tensor = out

    n_elements = x_contig.numel()
    if n_elements > 0:
        grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
        compute_fp32 = x_contig.dtype in (torch.float16, torch.bfloat16)
        _erf_kernel[grid](
            x_contig.view(-1),
            out_tensor.view(-1),
            n_elements,
            BLOCK_SIZE=1024,
            COMPUTE_FP32=compute_fp32,
        )

    if out is not None:
        if out.shape != out_tensor.shape:
            raise ValueError("out must have the same shape as input/result")
        if out.device != out_tensor.device:
            raise ValueError("out must be on the same device as input")
        if out.dtype != out_tensor.dtype:
            raise ValueError("out must have the same dtype as the result")
        if out is not out_tensor:
            out.copy_(out_tensor)
        return out

    return out_tensor.view(x.shape)

