import math
from collections import namedtuple

import torch
import triton
import triton.language as tl


MinGeluResult = namedtuple("min", ["values", "indices"])


@triton.jit
def _gelu_none(x):
    x_f = x.to(tl.float32)
    return 0.5 * x_f * (1.0 + tl.erf(x_f * 0.7071067811865475))


@triton.jit
def _gelu_tanh(x):
    x_f = x.to(tl.float32)
    x3 = x_f * x_f * x_f
    inner = 0.7978845608028654 * (x_f + 0.044715 * x3)
    return 0.5 * x_f * (1.0 + tl.tanh(inner))


@triton.jit
def _min_gelu_reduce_kernel(
    x_ptr,
    values_ptr,
    indices_ptr,
    M,
    K,
    approximate_mode: tl.constexpr,
    BLOCK_K: tl.constexpr,
):
    row = tl.program_id(0)

    min_val = tl.full((1,), float("inf"), tl.float32)
    min_idx = tl.zeros((1,), tl.int64)

    for start in range(0, K, BLOCK_K):
        offs = start + tl.arange(0, BLOCK_K)
        mask = offs < K
        x = tl.load(x_ptr + row * K + offs, mask=mask, other=0.0)

        if approximate_mode == 0:
            y = _gelu_none(x)
        else:
            y = _gelu_tanh(x)

        y = tl.where(mask, y, float("inf"))
        block_min = tl.min(y, axis=0)
        eq_mask = y == block_min
        cand_idx = tl.where(eq_mask, offs.to(tl.int64), tl.full((BLOCK_K,), K, tl.int64))
        block_idx = tl.min(cand_idx, axis=0)

        better = block_min < min_val
        min_val = tl.where(better, block_min, min_val)
        min_idx = tl.where(better, block_idx, min_idx)

    tl.store(values_ptr + row, min_val)
    tl.store(indices_ptr + row, min_idx)


def _normalize_dim(dim, ndim):
    if dim < 0:
        dim += ndim
    if dim < 0 or dim >= ndim:
        raise IndexError(f"Dimension out of range (expected to be in range of [{-ndim}, {ndim - 1}], but got {dim})")
    return dim


def _choose_block_k(k):
    if k <= 128:
        return 128
    if k <= 256:
        return 256
    if k <= 512:
        return 512
    if k <= 1024:
        return 1024
    return 2048


def min_gelu(input, dim=None, keepdim=False, approximate='none', out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if not input.dtype.is_floating_point:
        raise TypeError("gelu is only defined for floating point tensors")
    if approximate not in ("none", "tanh"):
        raise ValueError("approximate must be either 'none' or 'tanh'")

    approximate_mode = 0 if approximate == "none" else 1

    if dim is None:
        if input.numel() == 0:
            raise RuntimeError("min(): Expected reduction dim to be specified for input.numel() == 0.")
        x = input.contiguous().view(1, input.numel())
        block_k = _choose_block_k(x.shape[1])

        if out is None:
            values_fp32 = torch.empty((1,), device=input.device, dtype=torch.float32)
        else:
            if not isinstance(out, torch.Tensor):
                raise TypeError("out must be a torch.Tensor when dim is None")
            if out.device != input.device:
                raise ValueError("out must be on the same device as input")
            if out.numel() != 1:
                raise ValueError("out must have one element when dim is None")
            values_fp32 = torch.empty((1,), device=input.device, dtype=torch.float32)

        indices_tmp = torch.empty((1,), device=input.device, dtype=torch.int64)

        grid = (1,)
        _min_gelu_reduce_kernel[grid](
            x,
            values_fp32,
            indices_tmp,
            1,
            x.shape[1],
            approximate_mode=approximate_mode,
            BLOCK_K=block_k,
        )

        result = values_fp32.to(dtype=input.dtype).reshape(())
        if out is not None:
            out.copy_(result)
            return out
        return result

    if input.ndim == 0:
        raise IndexError("Dimension out of range (expected to be in range of [0, -1], but got 0)")

    dim = _normalize_dim(dim, input.ndim)
    if input.shape[dim] == 0:
        raise IndexError("min(): Expected reduction dim 0 to have non-zero size.")

    order = [i for i in range(input.ndim) if i != dim] + [dim]
    x = input.permute(order).contiguous()
    k = x.shape[-1]
    m = x.numel() // k
    x2d = x.view(m, k)

    block_k = _choose_block_k(k)
    values_fp32 = torch.empty((m,), device=input.device, dtype=torch.float32)
    indices_flat = torch.empty((m,), device=input.device, dtype=torch.int64)

    grid = (m,)
    _min_gelu_reduce_kernel[grid](
        x2d,
        values_fp32,
        indices_flat,
        m,
        k,
        approximate_mode=approximate_mode,
        BLOCK_K=block_k,
    )

    reduced_shape = [input.shape[i] for i in range(input.ndim) if i != dim]
    values = values_fp32.to(dtype=input.dtype).view(reduced_shape)
    indices = indices_flat.view(reduced_shape)

    if keepdim:
        out_shape = list(input.shape)
        out_shape[dim] = 1
        values = values.view(out_shape)
        indices = indices.view(out_shape)

