import math
from collections import namedtuple

import torch
import triton
import triton.language as tl


MinGeluResult = namedtuple("min", ["values", "indices"])


@triton.jit
def _gelu_none(x):
    x_f = x.to(tl.float32)
    return 0.5 * x_f * (1.0 + tl.erf(x_f * 0.7071067811865475))


@triton.jit
def _gelu_tanh(x):
    x_f = x.to(tl.float32)
    x3 = x_f * x_f * x_f
    inner = 0.7978845608028654 * (x_f + 0.044715 * x3)
    return 0.5 * x_f * (1.0 + tl.tanh(inner))


@triton.jit
def _min_gelu_reduce_kernel(
    x_ptr,
    values_ptr,
    indices_ptr,
    M,
    K,
    approximate_mode: tl.constexpr,
    BLOCK_K: tl.constexpr,
):
    row = tl.program_id(0)

    min_val = tl.full((1,), float("inf"), tl.float32)
    min_idx = tl.zeros((1,), tl.int64)

    for start in range(0, K, BLOCK_K):
        offs = start + tl.arange(0, BLOCK_K)
        mask = offs < K
        x = tl.load(x_ptr + row * K + offs, mask=mask, other=0.0)

        if approximate_mode == 0:
            y = _gelu_none(x)
        else:
            y = _gelu_tanh(x)

        y = tl.where(mask, y, float("inf"))
        block_min = tl.min(y, axis=0)
        eq_mask = y == block_min
        cand_idx = tl.where(eq_mask, offs.to(tl.int64), tl.full((BLOCK_K,), K, tl.int64))
        block_idx = tl.min(cand_idx, axis=0)

        better = block_min < min_val
        min_val = tl.where(better, block_min, min_val)
        min_idx = tl.where(better, block_idx, min_idx)

    tl.store(values_ptr + row, min_val)
    tl.store(indices_ptr + row, min_idx)


