        if out.dtype != expected_dtype:
            raise ValueError("out must have the same dtype as input")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")

    if input.numel() == 0:
        return out

    input_contig = input.contiguous()
    need_temp_out = not out.is_contiguous()
    out_contig = torch.empty_like(input_contig) if need_temp_out else out.view(-1)

    x_flat = input_contig.view(-1)
    y_flat = out_contig if need_temp_out else out_contig

