import triton
import triton.language as tl
import torch

_rand_call_counter = 0


@triton.jit
def _hash_u32(x):
    x = tl.cast(x, tl.uint32)
    x = x ^ (x >> 16)
    x = x * tl.full((), 0x7FEB352D, tl.uint32)
    x = x ^ (x >> 15)
    x = x * tl.full((), 0x846CA68B, tl.uint32)
    x = x ^ (x >> 16)
    return x


@triton.jit
def _rand_fill_strided_kernel(
    out_ptr,
    shape_ptr,
    stride_ptr,
    numel,
    seed,
    BLOCK_SIZE: tl.constexpr,
    NDIM: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < numel

    linear = tl.cast(offs, tl.int64)
    rem = linear
    mem_offs = tl.zeros([BLOCK_SIZE], dtype=tl.int64)

    for d in tl.static_range(NDIM):
        size_d = tl.load(shape_ptr + d)
        stride_d = tl.load(stride_ptr + d)
        idx_d = rem % size_d
        rem = rem // size_d
        mem_offs += idx_d * stride_d

    rnd_u32 = _hash_u32(tl.cast(offs, tl.uint32) ^ seed)
    vals = tl.cast(rnd_u32, tl.float32) * (1.0 / 4294967296.0)
    tl.store(out_ptr + mem_offs, vals, mask=mask)


def rand(*size, generator=None, out=None, dtype=None, layout=torch.strided, device=None, requires_grad=False, pin_memory=False):
    global _rand_call_counter

    if len(size) == 1 and isinstance(size[0], (tuple, list, torch.Size)):
        size = tuple(size[0])
    else:
        size = tuple(size)

    for s in size:
        if not isinstance(s, int):
            raise TypeError("size must be a sequence of integers")
        if s < 0:
            raise RuntimeError("Trying to create tensor with negative dimension")

    if layout is not torch.strided:
        raise NotImplementedError("Only torch.strided layout is supported")
    if pin_memory:
        raise NotImplementedError("pin_memory=True is not supported")
    if len(size) > 16:
        raise NotImplementedError("Tensors with more than 16 dimensions are not supported")

