            raise RuntimeError("device must match out.device when out is provided")
        if dtype is not None and dtype != out.dtype:
            raise RuntimeError("dtype must match out.dtype when out is provided")
        if out.layout is not torch.strided:
            raise NotImplementedError("Only torch.strided out tensors are supported")
        if out.device.type != "cuda":
            raise NotImplementedError("Only CUDA tensors are supported")
        if out.is_complex():
            raise NotImplementedError("Complex dtypes are not supported")
        if not out.dtype.is_floating_point:
            raise NotImplementedError("Only floating point dtypes are supported")
        result = out
        if requires_grad and not result.dtype.is_floating_point:
            raise RuntimeError("Only Tensors of floating point dtype can require gradients")
        result.requires_grad_(requires_grad)
    else:
        if dtype is None:
            dtype = torch.get_default_dtype()
        if not isinstance(dtype, torch.dtype):
            raise TypeError("dtype must be a torch.dtype")
        if dtype.is_complex:
            raise NotImplementedError("Complex dtypes are not supported")
        if not dtype.is_floating_point:
            raise NotImplementedError("Only floating point dtypes are supported")

        if device is None:
            if torch.cuda.is_available():
                resolved_device = torch.device("cuda", torch.cuda.current_device())
            else:
                raise NotImplementedError("Only CUDA devices are supported")
        else:
            resolved_device = torch.device(device)

        if resolved_device.type != "cuda":
            raise NotImplementedError("Only CUDA devices are supported")

