    seed = (base_seed + _rand_call_counter) & 0xFFFFFFFF
    _rand_call_counter += 1

    shape_t = torch.tensor(size, device=result.device, dtype=torch.int64)
    stride_t = torch.tensor(result.stride(), device=result.device, dtype=torch.int64)

    block_size = 1024
    grid = (triton.cdiv(numel, block_size),)

