import triton
import triton.language as tl
import torch


def _broadcast_shape(shapes):
    if not shapes:
        return ()
    max_ndim = max(len(s) for s in shapes)
    result = [1] * max_ndim
    for shape in shapes:
        offset = max_ndim - len(shape)
        for i, size in enumerate(shape):
            dim = offset + i
            cur = result[dim]
            if cur == 1:
                result[dim] = size
            elif size == 1 or size == cur:
                continue
            else:
                raise RuntimeError(
                    "The size of tensor a ({}) must match the size of tensor b ({}) at non-singleton dimension {}".format(
                        cur, size, dim
                    )
                )
    return tuple(result)


def _expanded_stride(tensor, target_shape):
    in_shape = tuple(tensor.shape)
    in_stride = tuple(tensor.stride())
    max_ndim = len(target_shape)
    offset = max_ndim - len(in_shape)
    out_stride = [0] * max_ndim
    for dim in range(max_ndim - 1, -1, -1):
        if dim < offset:
            out_stride[dim] = 0
            continue
        src_dim = dim - offset
        src_size = in_shape[src_dim]
        tgt_size = target_shape[dim]
        if src_size == tgt_size:
            out_stride[dim] = in_stride[src_dim]
        elif src_size == 1:
            out_stride[dim] = 0
        else:
            raise RuntimeError(
                "The expanded size of the tensor ({}) must match the existing size ({}) at non-singleton dimension {}".format(
                    tgt_size, src_size, dim
                )
            )
    return tuple(out_stride)


def broadcast_tensors(*tensors):
    if len(tensors) == 0:
        return []
    for t in tensors:
        if not isinstance(t, torch.Tensor):
            raise TypeError("broadcast_tensors(): expected Tensor as input")
    target_shape = _broadcast_shape([tuple(t.shape) for t in tensors])
    outputs = []
    for t in tensors:
        if tuple(t.shape) == target_shape:
            outputs.append(t)
            continue
        stride = _expanded_stride(t, target_shape)
        outputs.append(torch.as_strided(t, size=target_shape, stride=stride, storage_offset=t.storage_offset()))
    return outputs

