import triton
import triton.language as tl
import torch


@triton.jit
def _mul_sub_kernel(
    input_ptr,
    other_mul_ptr,
    other_sub_ptr,
    out_ptr,
    shape_ptr,
    in_stride_ptr,
    mul_stride_ptr,
    sub_stride_ptr,
    out_stride_ptr,
    numel,
    alpha,
    HAS_MUL_TENSOR: tl.constexpr,
    HAS_SUB_TENSOR: tl.constexpr,
    NDIMS: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < numel

    rem = offs.to(tl.int64)

    in_off = tl.zeros([BLOCK_SIZE], dtype=tl.int64)
    mul_off = tl.zeros([BLOCK_SIZE], dtype=tl.int64)
    sub_off = tl.zeros([BLOCK_SIZE], dtype=tl.int64)
    out_off = tl.zeros([BLOCK_SIZE], dtype=tl.int64)

    for d in tl.static_range(NDIMS - 1, -1, -1):
        dim_sz = tl.load(shape_ptr + d)
        idx = rem % dim_sz
        rem = rem // dim_sz

        in_stride = tl.load(in_stride_ptr + d)
        out_stride = tl.load(out_stride_ptr + d)
        in_off += idx * in_stride
        out_off += idx * out_stride

        if HAS_MUL_TENSOR:
            mul_stride = tl.load(mul_stride_ptr + d)
            mul_off += idx * mul_stride

        if HAS_SUB_TENSOR:
            sub_stride = tl.load(sub_stride_ptr + d)
            sub_off += idx * sub_stride

    x = tl.load(input_ptr + in_off, mask=mask)

    if HAS_MUL_TENSOR:
        y = tl.load(other_mul_ptr + mul_off, mask=mask)
    else:
        y = other_mul_ptr

    if HAS_SUB_TENSOR:
        z = tl.load(other_sub_ptr + sub_off, mask=mask)
    else:
        z = other_sub_ptr

    out_val = x * y - alpha * z
    tl.store(out_ptr + out_off, out_val, mask=mask)


def _is_tensor(x):
    return isinstance(x, torch.Tensor)


def _compute_broadcast_shape(input, other_mul, other_sub):
    shapes = [tuple(input.shape)]
    if _is_tensor(other_mul):
        shapes.append(tuple(other_mul.shape))
    if _is_tensor(other_sub):
        shapes.append(tuple(other_sub.shape))
    return torch.broadcast_shapes(*shapes)


def _padded_shape_and_stride(tensor, out_shape, ndims, device):
    if tensor is None:
        shape = [1] * ndims
        stride = [0] * ndims
    else:
        t_shape = list(tensor.shape)
        t_stride = list(tensor.stride())
        shape = [1] * ndims
        stride = [0] * ndims
        offset = ndims - len(t_shape)
        for i in range(len(t_shape)):
            s = t_shape[i]
            shape[offset + i] = s
            if s == 1 and out_shape[offset + i] != 1:
                stride[offset + i] = 0
            else:
                stride[offset + i] = t_stride[i]
    shape_t = torch.tensor(shape, device=device, dtype=torch.int64)
    stride_t = torch.tensor(stride, device=device, dtype=torch.int64)
    return shape_t, stride_t


def _result_dtype(input, other_mul, other_sub, alpha, device):
    mul_dtype = torch.result_type(input, other_mul)
    mul_meta = torch.empty((), device=device, dtype=mul_dtype)
    if _is_tensor(other_sub):
        sub_meta = other_sub
    else:
        sub_meta = torch.tensor(other_sub, device=device)
    alpha_meta = torch.tensor(alpha, device=device)
    scaled_sub_dtype = torch.result_type(sub_meta, alpha_meta)
    scaled_sub_meta = torch.empty((), device=device, dtype=scaled_sub_dtype)
    return torch.result_type(mul_meta, scaled_sub_meta)


def mul_sub(input, other_mul, other_sub, alpha=1, out=None) -> torch.Tensor:
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if _is_tensor(other_mul) and not other_mul.is_cuda:
        raise ValueError("other_mul must be a CUDA tensor when provided as a tensor")
    if _is_tensor(other_sub) and not other_sub.is_cuda:
        raise ValueError("other_sub must be a CUDA tensor when provided as a tensor")

    device = input.device
    out_shape = _compute_broadcast_shape(input, other_mul, other_sub)
    ndims = len(out_shape)

    if ndims == 0:
        out_shape = ()
        ndims = 1
        shape_meta = torch.tensor([1], device=device, dtype=torch.int64)
    else:
        shape_meta = torch.tensor(list(out_shape), device=device, dtype=torch.int64)

    if ndims < 1:
        ndims = 1

    if len(out_shape) > 16:
        raise ValueError("mul_sub supports up to 16 dimensions")

    result_dtype = _result_dtype(input, other_mul, other_sub, alpha, device)

    if out is None:
        out = torch.empty(out_shape, device=device, dtype=result_dtype)
    else:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if not out.is_cuda:
            raise ValueError("out must be a CUDA tensor")
        if tuple(out.shape) != tuple(out_shape):
            raise ValueError("out has incorrect shape")
        if out.device != device:
            raise ValueError("out must be on the same device as input")

    _, in_stride = _padded_shape_and_stride(input, out_shape if len(out_shape) > 0 else (1,), ndims, device)
    _, out_stride = _padded_shape_and_stride(out, out_shape if len(out_shape) > 0 else (1,), ndims, device)

    has_mul_tensor = _is_tensor(other_mul)
    has_sub_tensor = _is_tensor(other_sub)

    if has_mul_tensor:
        _, mul_stride = _padded_shape_and_stride(other_mul, out_shape if len(out_shape) > 0 else (1,), ndims, device)
        mul_arg = other_mul
    else:
        mul_stride = torch.zeros((ndims,), device=device, dtype=torch.int64)
        mul_arg = other_mul

    if has_sub_tensor:
        _, sub_stride = _padded_shape_and_stride(other_sub, out_shape if len(out_shape) > 0 else (1,), ndims, device)
        sub_arg = other_sub
    else:
        sub_stride = torch.zeros((ndims,), device=device, dtype=torch.int64)
        sub_arg = other_sub

    if input.dtype != result_dtype:
        input_arg = input.to(result_dtype)
    else:
        input_arg = input

    if has_mul_tensor and other_mul.dtype != result_dtype:
        mul_arg = other_mul.to(result_dtype)
    if has_sub_tensor and other_sub.dtype != result_dtype:
        sub_arg = other_sub.to(result_dtype)

    if out.dtype != result_dtype:
        compute_out = torch.empty(out_shape, device=device, dtype=result_dtype)
    else:
        compute_out = out

    numel = compute_out.numel()
    if numel == 0:
        return out

    BLOCK_SIZE = 256
    grid = (triton.cdiv(numel, BLOCK_SIZE),)

    kernel_kwargs = {
        "HAS_MUL_TENSOR": has_mul_tensor,
        "HAS_SUB_TENSOR": has_sub_tensor,
        "NDIMS": ndims,
        "BLOCK_SIZE": BLOCK_SIZE,
    }

    _mul_sub_kernel[grid](
        input_arg,
        mul_arg,
        sub_arg,
        compute_out,
        shape_meta,
        in_stride,
        mul_stride,
        sub_stride,
        out_stride,
        numel,
        alpha,
        **kernel_kwargs,
    )

    if compute_out is not out:
        out.copy_(compute_out)

    return out

