import copy
import triton
import triton.language as tl
import torch


def quantize_dynamic(model, qconfig_spec=None, inplace=False, mapping=None):
    if not inplace:
        model = copy.deepcopy(model)

    ao_quant = getattr(torch, "ao", None)
    if ao_quant is not None and hasattr(torch.ao, "quantization") and hasattr(torch.ao.quantization, "quantize_dynamic"):
        return torch.ao.quantization.quantize_dynamic(
            model,
            qconfig_spec=qconfig_spec,
            inplace=True,
            mapping=mapping,
        )

    if hasattr(torch, "quantization") and hasattr(torch.quantization, "quantize_dynamic"):
        return torch.quantization.quantize_dynamic(
            model,
            qconfig_spec=qconfig_spec,
            inplace=True,
            mapping=mapping,
        )

    raise RuntimeError("quantize_dynamic is not available in this PyTorch installation.")

