import triton
import triton.language as tl
import torch


@triton.jit
def _ones_like_kernel(out_ptr, n_elements, ONE: tl.constexpr, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    offsets = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    vals = tl.full((BLOCK_SIZE,), ONE, dtype=tl.float32)
    tl.store(out_ptr + offsets, vals, mask=mask)


def ones_like(input, *, dtype=None, layout=None, device=None, requires_grad=False, memory_format=torch.preserve_format):
    if dtype is None:
        dtype = input.dtype
    if layout is None:
        layout = input.layout
    if device is None:
        device = input.device

    if layout != torch.strided:
        raise NotImplementedError("Triton ones_like only supports torch.strided layout")
    if device.type != "cuda":
        raise ValueError("Triton ones_like only supports CUDA tensors")

    out = torch.empty(
        input.size(),
        dtype=dtype,
        layout=layout,
        device=device,
        requires_grad=requires_grad,
    )

    n_elements = out.numel()
    if n_elements == 0:
        return out

    def grid(meta):
        return (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)

    _ones_like_kernel[grid](
        out,
        n_elements,
        ONE=1,
        BLOCK_SIZE=1024,
    )
    return out

