import triton
import triton.language as tl
import torch


@triton.jit
def _reciprocal_kernel(
    in_ptr,
    out_ptr,
    n_elements,
    BLOCK_SIZE: tl.constexpr,
    DTYPE_CODE: tl.constexpr,
):
    pid = tl.program_id(0)
    offs = pid * BLOCK_SIZE + tl.arange(0, BLOCK_SIZE)
    mask = offs < n_elements

    x = tl.load(in_ptr + offs, mask=mask, other=0)

    if DTYPE_CODE == 0:
        x = tl.cast(x, tl.float16)
        one = tl.full((BLOCK_SIZE,), 1, tl.float16)
    elif DTYPE_CODE == 1:
        x = tl.cast(x, tl.bfloat16)
        one = tl.full((BLOCK_SIZE,), 1, tl.bfloat16)
    elif DTYPE_CODE == 2:
        x = tl.cast(x, tl.float32)
        one = tl.full((BLOCK_SIZE,), 1, tl.float32)
    else:
        x = tl.cast(x, tl.float64)
        one = tl.full((BLOCK_SIZE,), 1, tl.float64)

    y = one / x
    tl.store(out_ptr + offs, y, mask=mask)


def _dtype_code(dtype):
    if dtype == torch.float16:
        return 0
    if dtype == torch.bfloat16:
        return 1
    if dtype == torch.float32:
        return 2
    if dtype == torch.float64:
        return 3
    raise TypeError(f"unsupported output dtype for reciprocal: {dtype}")


def reciprocal(input, *, out=None):
    if not isinstance(input, torch.Tensor):
        raise TypeError("input must be a torch.Tensor")
    if not input.is_cuda:
        raise ValueError("input must be a CUDA tensor")
    if input.is_complex():
        raise TypeError("complex tensors are not supported by this Triton implementation")

    if input.is_floating_point():
        result_dtype = input.dtype
    else:
        result_dtype = torch.get_default_dtype()

    if result_dtype not in (torch.float16, torch.bfloat16, torch.float32, torch.float64):
        raise TypeError(f"unsupported result dtype for reciprocal: {result_dtype}")

    if out is not None:
        if not isinstance(out, torch.Tensor):
            raise TypeError("out must be a torch.Tensor")
        if out.device != input.device:
            raise ValueError("out must be on the same device as input")
        if tuple(out.shape) != tuple(input.shape):
            raise ValueError("out must have the same shape as input")

    in_contig = input.contiguous()
    need_temp_out = (
        out is None
        or not out.is_contiguous()
        or out.dtype != result_dtype
    )

    if need_temp_out:
        result = torch.empty(input.shape, device=input.device, dtype=result_dtype)
    else:
        result = out

    n_elements = in_contig.numel()
    if n_elements > 0:
        flat_in = in_contig.reshape(-1)
        flat_out = result.reshape(-1)
        grid = lambda meta: (triton.cdiv(n_elements, meta["BLOCK_SIZE"]),)
        _reciprocal_kernel[grid](
            flat_in,
            flat_out,
            n_elements,
            BLOCK_SIZE=1024,
            DTYPE_CODE=_dtype_code(result_dtype),
        )

    if out is not None:
        if result is not out:
            out.copy_(result)
        return out
    return result

